"""
Parameterized generator for GH814_psycopg_1197.

Source PR:    https://github.com/psycopg/psycopg/pull/1197
Source Issue: N/A

Seed varies: renames 'aarch64' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH814_psycopg_1197'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH814_psycopg_1197'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('aarch64', 'aarch64' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH814_psycopg_1197',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'psycopg/psycopg',
                "pr_number": 1197,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/psycopg/psycopg/pull/1197",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            '.github/workflows/build-and-cache-libpq.yml': 'name: Build and cache libpq\n\n# Build the libpq package and cache the artifacts.\n#\n# Every Python version on the same architecture will use the same libpq.\n# Therefore building and caching the libpq together with the binary packages\n# result in multiple concurrent builds, and the github artifacts manageer very\n# confused.\n#\n# This job builds the libpq and then caches the artifacts so that the\n# packages-bin.yml workflow will find the library in the cache.\n#\n# You can see the caches at https://github.com/psycopg/psycopg/actions/caches\n#\n# Or from the API:\n#\n#   curl -fsSL -X GET \\\n#     -H "Accept: application/vnd.github+json" \\\n#     -H "Authorization: Bearer $GITHUB_TOKEN" \\\n#     -H "X-GitHub-Api-Version: 2022-11-28" \\\n#     "https://api.github.com/repos/psycopg/psycopg/actions/caches" \\\n#   | jq -r \'.actions_caches[].key\'\n#\n# You can delete a cache using:\n#\n#   curl -fsSL -X DELETE \\\n#     -H "Accept: application/vnd.github+json" \\\n#     -H "Authorization: Bearer $GITHUB_TOKEN" \\\n#     -H "X-GitHub-Api-Version: 2022-11-28" \\\n#     "https://api.github.com/repos/psycopg/psycopg/actions/caches?key=libpq-manylinux-ppc64le-17.2-3.4.0"\n#\n# ref: https://docs.github.com/en/rest/actions/cache?apiVersion=2022-11-28#delete-github-actions-caches-for-a-repository-using-a-cache-key\n\non:\n  workflow_dispatch:\n  push:\n    paths:\n      - .github/workflows/build-and-cache-libpq.yml\n\n# TODO: move these env vars in an external env file in order to share them\n# across workflows.\n\nenv:\n  # Latest release: https://www.postgresql.org/ftp/source/\n  LIBPQ_VERSION: "18.0"\n  # Note: On windows the latest version can be found at\n  # https://vcpkg.io/en/package/libpq\n  # However the command line tool doesn\'t have a flag to specify to install\n  # a specific version, so whatever you get you keep it.\n  # https://github.com/microsoft/vcpkg/discussions/25622\n\n  # Latest release: https://www.openssl.org/source/\n  OPENSSL_VERSION: "3.5.4"\n\n  # A string to differentiate build cacke keys to allow building different\n  # flavours of libpq in different branches without mixups. Currently used to\n  # make sure that libpq packages built for Psycopg 3.2 and 3.3 don\'t mix (in\n  # order to change the gssencmode default only on 3.3). We may use it for\n  # different reasons in the future.\n  PQ_FLAGS: "-gssencmode-disable"\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n\n  linux:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, ppc64le, aarch64]\n        platform: [manylinux, musllinux]\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - name: Set up QEMU for multi-arch build\n        # Check https://github.com/docker/setup-qemu-action for newer versions.\n        uses: docker/setup-qemu-action@v3\n        with:\n          # https://github.com/pypa/cibuildwheel/discussions/2256\n          image: tonistiigi/binfmt:qemu-v8.1.5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-${{ matrix.platform }}-${{ matrix.arch }}-${{ env.LIBPQ_VERSION }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.0\n        with:\n          package-dir: psycopg_c\n        env:\n          CIBW_MANYLINUX_X86_64_IMAGE: manylinux2014\n          CIBW_MANYLINUX_I686_IMAGE: manylinux2014\n          CIBW_MANYLINUX_AARCH64_IMAGE: manylinux_2_28\n          CIBW_MANYLINUX_PPC64LE_IMAGE: manylinux2014\n          CIBW_BUILD: cp313-${{matrix.platform}}_${{matrix.arch}}\n          CIBW_ARCHS_LINUX: auto aarch64 ppc64le\n          CIBW_BEFORE_ALL_LINUX: ./tools/ci/build_libpq.sh\n          CIBW_REPAIR_WHEEL_COMMAND: >-\n            ./tools/ci/strip_wheel.sh {wheel}\n            && auditwheel repair -w {dest_dir} {wheel}\n          CIBW_ENVIRONMENT_PASS_LINUX: LIBPQ_VERSION OPENSSL_VERSION\n          CIBW_ENVIRONMENT: >-\n            LIBPQ_BUILD_PREFIX=/host/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            LD_LIBRARY_PATH="$LIBPQ_BUILD_PREFIX/lib:$LIBPQ_BUILD_PREFIX/lib64"\n\n\n  # }}}\n\n  macos:  # {{{\n    runs-on: macos-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, arm64]\n\n    steps:\n      - name: Checkout repos\n        uses: actions/checkout@v5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-macos-${{ env.LIBPQ_VERSION }}-${{ matrix.arch }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.0\n        with:\n          package-dir: psycopg_c\n        env:\n          CIBW_BUILD: cp313-macosx_${{matrix.arch}}\n          CIBW_ARCHS_MACOS: ${{matrix.arch}}\n          MACOSX_ARCHITECTURE: ${{matrix.arch}}\n          CIBW_BEFORE_ALL_MACOS: ./tools/ci/build_libpq.sh\n          CIBW_ENVIRONMENT: >-\n            PSYCOPG_IMPL=binary\n            LIBPQ_BUILD_PREFIX=/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n\n  # }}}\n',
            '.github/workflows/packages-bin.yml': 'name: Build binary packages\n\n# Note: these jobs also build and cache the libpq, but, because every Python\n# version will try to build and cache the same libpq instance, there is a race\n# condition and most likely the artifacts manager will refuse to cache.\n#\n# Please run the `build-and-cache-libpq.yml` workflow when the libpq/openssl\n# version change in order to update the cache.\n\non:\n  push:\n    paths:\n      - \'.github/workflows/packages-bin.yml\'\n  workflow_dispatch:\n  schedule:\n    - cron: \'28 7 * * sun\'\n\nenv:\n  # Latest release: https://www.postgresql.org/ftp/source/\n  LIBPQ_VERSION: "18.0"\n  # Note: On windows the latest version can be found at\n  # https://vcpkg.io/en/package/libpq\n  # However the command line tool doesn\'t have a flag to specify to install\n  # a specific version, so whatever you get you keep it.\n  # https://github.com/microsoft/vcpkg/discussions/25622\n\n  # Latest release: https://www.openssl.org/source/\n  OPENSSL_VERSION: "3.5.4"\n\n  # A string to differentiate build cacke keys to allow building different\n  # flavours of libpq in different branches without mixups. Currently used to\n  # make sure that libpq packages built for Psycopg 3.2 and 3.3 don\'t mix (in\n  # order to change the gssencmode default only on 3.3). We may use it for\n  # different reasons in the future.\n  PQ_FLAGS: "-gssencmode-disable"\n\nconcurrency:\n  # Cancel older requests of the same workflow in the same branch.\n  group: ${{ github.workflow }}-${{ github.ref_name }}\n  cancel-in-progress: true\n\njobs:\n\n  linux:  # {{{\n    runs-on: ubuntu-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, ppc64le, aarch64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n        platform: [manylinux, musllinux]\n\n    steps:\n      - uses: actions/checkout@v5\n\n      - name: Set up QEMU for multi-arch build\n        # Check https://github.com/docker/setup-qemu-action for newer versions.\n        uses: docker/setup-qemu-action@v3\n        with:\n          # https://github.com/pypa/cibuildwheel/discussions/2256\n          image: tonistiigi/binfmt:qemu-v8.1.5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-${{ matrix.platform }}-${{ matrix.arch }}-${{ env.LIBPQ_VERSION }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.0\n        with:\n          package-dir: psycopg_binary\n        env:\n          CIBW_MANYLINUX_X86_64_IMAGE: manylinux2014\n          CIBW_MANYLINUX_AARCH64_IMAGE: manylinux_2_28\n          CIBW_MANYLINUX_PPC64LE_IMAGE: manylinux2014\n          CIBW_BUILD: ${{matrix.pyver}}-${{matrix.platform}}_${{matrix.arch}}\n          CIBW_ARCHS_LINUX: auto aarch64 ppc64le\n          CIBW_BEFORE_ALL_LINUX: ./tools/ci/wheel_linux_before_all.sh\n          CIBW_REPAIR_WHEEL_COMMAND: >-\n            ./tools/ci/strip_wheel.sh {wheel}\n            && auditwheel repair -w {dest_dir} {wheel}\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT_PASS_LINUX: LIBPQ_VERSION OPENSSL_VERSION\n          CIBW_ENVIRONMENT: >-\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN=\'host=172.17.0.1 user=postgres\'\n            PGPASSWORD=password\n            LIBPQ_BUILD_PREFIX=/host/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            LD_LIBRARY_PATH="$LIBPQ_BUILD_PREFIX/lib:$LIBPQ_BUILD_PREFIX/lib64"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=${{ env.LIBPQ_VERSION }}\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=${{ env.LIBPQ_VERSION }}\n            PYTEST_ADDOPTS="-m \'not slow and not flakey\' --color yes"\n\n      - uses: actions/upload-artifact@v4\n        with:\n          name: linux-${{matrix.pyver}}-${{matrix.platform}}_${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n    services:\n      postgresql:\n        image: postgres:14\n        env:\n          POSTGRES_PASSWORD: password\n        ports:\n          - 5432:5432\n        # Set health checks to wait until postgres has started\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n          --health-timeout 5s\n          --health-retries 5\n\n\n  # }}}\n\n  macos:  # {{{\n    runs-on: macos-latest\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [x86_64, arm64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n\n    steps:\n      - name: Checkout repos\n        uses: actions/checkout@v5\n\n      - name: Cache libpq build\n        uses: actions/cache@v4\n        with:\n          path: /tmp/libpq.build\n          key: libpq-macos-${{ env.LIBPQ_VERSION }}-${{ matrix.arch }}-${{ env.OPENSSL_VERSION }}${{ env.PQ_FLAGS }}\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.0\n        with:\n          package-dir: psycopg_binary\n        env:\n          CIBW_BUILD: ${{matrix.pyver}}-macosx_${{matrix.arch}}\n          CIBW_ARCHS_MACOS: ${{matrix.arch}}\n          MACOSX_ARCHITECTURE: ${{matrix.arch}}\n          CIBW_BEFORE_ALL_MACOS: ./tools/ci/wheel_macos_before_all.sh\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT: >-\n            PG_VERSION=18\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN=\'dbname=postgres\'\n            LIBPQ_BUILD_PREFIX=/tmp/libpq.build\n            PATH="$LIBPQ_BUILD_PREFIX/bin:$PATH"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=">= ${{env.LIBPQ_VERSION}}"\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=">= ${{env.LIBPQ_VERSION}}"\n            PYTEST_ADDOPTS="-m \'not slow and not flakey and not proxy\' --color yes"\n\n      - name: Upload artifacts\n        uses: actions/upload-artifact@v4\n        with:\n          name: macos-${{matrix.pyver}}-${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n\n  # }}}\n\n  windows:  # {{{\n    # TODO: move it back to windows-latest when the default runner switches.\n    runs-on: windows-2025\n    if: true\n\n    strategy:\n      fail-fast: false\n      matrix:\n        arch: [win_amd64]\n        pyver: [cp310, cp311, cp312, cp313, cp314]\n\n    defaults:\n      run:\n        shell: bash\n\n    steps:\n      # there are some other libpq in PATH\n      - run: rm -rf c:/tools/php C:/Strawberry/c/bin\n\n      - uses: actions/checkout@v5\n\n      - name: Start PostgreSQL service for test\n        run: |\n          $PgSvc = Get-Service "postgresql*"\n          Set-Service $PgSvc.Name -StartupType manual\n          $PgSvc.Start()\n        shell: powershell\n\n      - name: Export GitHub Actions cache environment variables\n        uses: actions/github-script@v8\n        with:\n          script: |\n            const path = require(\'path\')\n            core.exportVariable(\'ACTIONS_CACHE_URL\', process.env.ACTIONS_CACHE_URL || \'\');\n            core.exportVariable(\'ACTIONS_RUNTIME_TOKEN\', process.env.ACTIONS_RUNTIME_TOKEN || \'\');\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/lib\'));\n            core.addPath(path.join(process.env.VCPKG_INSTALLATION_ROOT, \'installed/x64-windows-release/bin\'));\n\n      - name: Create the binary package source tree\n        run: python3 ./tools/ci/copy_to_binary.py\n\n      - name: Build wheels\n        uses: pypa/cibuildwheel@v3.2.0\n        with:\n          package-dir: psycopg_binary\n        env:\n          VCPKG_BINARY_SOURCES: "clear;x-gha,readwrite" # cache vcpkg\n          CIBW_BUILD: ${{matrix.pyver}}-${{matrix.arch}}\n          CIBW_ARCHS_WINDOWS: AMD64 x86\n          CIBW_BEFORE_BUILD_WINDOWS: \'.\\tools\\ci\\wheel_win32_before_build.bat\'\n          CIBW_REPAIR_WHEEL_COMMAND_WINDOWS: >-\n            delvewheel repair -w {dest_dir}\n            --no-mangle "libiconv-2.dll;libwinpthread-1.dll" {wheel}\n          CIBW_TEST_REQUIRES: ./psycopg[test] ./psycopg_pool\n          CIBW_TEST_COMMAND: pytest {project}/tests\n          CIBW_ENVIRONMENT_WINDOWS: >-\n            PSYCOPG_IMPL=binary\n            PSYCOPG_TEST_DSN="host=127.0.0.1 user=postgres"\n            PSYCOPG_TEST_WANT_LIBPQ_BUILD=">= 16"\n            PSYCOPG_TEST_WANT_LIBPQ_IMPORT=">= 16"\n            PYTEST_ADDOPTS="-m \'not slow and not flakey and not proxy\' --color yes"\n\n      - uses: actions/upload-artifact@v4\n        with:\n          name: windows-${{matrix.pyver}}-${{matrix.arch}}\n          path: ./wheelhouse/*.whl\n\n\n  # }}}\n\n  merge:  # {{{\n    runs-on: ubuntu-latest\n    needs:\n      - linux\n      - macos\n      - windows\n    steps:\n      - name: Merge Artifacts\n        uses: actions/upload-artifact/merge@v4\n        with:\n          name: psycopg-binary-artifact\n          delete-merged: true\n\n  # }}}\n',
            'tools/ci/build_libpq.sh': '#!/bin/bash\n\n# Build a modern version of libpq and depending libs from source on Centos 5,\n# Alpine or macOS\n\nset -euo pipefail\n\npostgres_version="${LIBPQ_VERSION}"\nopenssl_version="${OPENSSL_VERSION}"\n\n# Latest release: https://kerberos.org/dist/\nkrb5_version="1.21.3"\n\n# Latest release: https://openldap.org/software/download/\nldap_version="2.6.9"\n\nexport LIBPQ_BUILD_PREFIX=${LIBPQ_BUILD_PREFIX:-/tmp/libpq.build}\n\ncase "$(uname)" in\n    Darwin)\n        ID=macos\n        library_suffix=dylib\n        ;;\n\n    Linux)\n        source /etc/os-release\n        library_suffix=so\n        ;;\n\n    *)\n        echo "$0: unexpected Operating system: \'$(uname)\'" >&2\n        exit 1\n        ;;\nesac\n\n# Install packages required for test and wheels build, regardless of whether\n# we will build the libpq or not.\ncase "$ID" in\n    alpine)\n        apk add --no-cache tzdata krb5-libs\n        ;;\nesac\n\nif [[ -f "${LIBPQ_BUILD_PREFIX}/lib/libpq.${library_suffix}" ]]; then\n    echo "libpq already available: build skipped" >&2\n    exit 0\nfi\n\n# Install packages required to build the libpq.\ncase "$ID" in\n    centos | almalinux)\n        yum update -y\n        yum install -y flex cyrus-sasl-devel krb5-devel pam-devel \\\n            perl-IPC-Cmd perl-Time-Piece zlib-devel\n        ;;\n\n    alpine)\n        apk upgrade\n        apk add --no-cache flex krb5-dev linux-pam-dev openldap-dev \\\n            openssl-dev zlib-dev\n        ;;\n\n    macos)\n        brew install automake cyrus-sasl libtool m4\n        # If available, libpq seemingly insists on linking against homebrew\'s\n        # openssl no matter what so remove it. Since homebrew\'s curl depends on\n        # it, force use of system curl.\n        brew uninstall --force --ignore-dependencies openssl gettext curl\n        if [ -z "${MACOSX_ARCHITECTURE:-}" ]; then\n            MACOSX_ARCHITECTURE="$(uname -m)"\n        fi\n        # Set the deployment target to be <= to that of the oldest supported Python version.\n        # e.g. https://www.python.org/downloads/release/python-380/\n        if [ "$MACOSX_ARCHITECTURE" == "x86_64" ]; then\n            export MACOSX_DEPLOYMENT_TARGET=10.9\n        else\n            export MACOSX_DEPLOYMENT_TARGET=11.0\n        fi\n        ;;\n\n    *)\n        echo "$0: unexpected Linux distribution: \'$ID\'" >&2\n        exit 1\n        ;;\nesac\n\n\nif [ "$ID" == "macos" ]; then\n    make_configure_standard_flags=( \\\n        --prefix=${LIBPQ_BUILD_PREFIX} \\\n        "CPPFLAGS=-I${LIBPQ_BUILD_PREFIX}/include/ -arch $MACOSX_ARCHITECTURE" \\\n        "LDFLAGS=-L${LIBPQ_BUILD_PREFIX}/lib -arch $MACOSX_ARCHITECTURE" \\\n    )\nelse\n    make_configure_standard_flags=( \\\n        --prefix=${LIBPQ_BUILD_PREFIX} \\\n        CPPFLAGS=-I${LIBPQ_BUILD_PREFIX}/include/ \\\n        "LDFLAGS=-L${LIBPQ_BUILD_PREFIX}/lib -L${LIBPQ_BUILD_PREFIX}/lib64" \\\n    )\nfi\n\nif [ "$ID" == "centos" ] || [ "$ID" == "almalinux" ]|| [ "$ID" == "macos" ]; then\n  if [[ ! -f "${LIBPQ_BUILD_PREFIX}/openssl.cnf" ]]; then\n\n    # Build openssl if needed\n    openssl_tag="openssl-${openssl_version}"\n    openssl_dir="openssl-${openssl_tag}"\n    if [ ! -d "${openssl_dir}" ]; then\n        curl -fsSL \\\n            https://github.com/openssl/openssl/archive/${openssl_tag}.tar.gz \\\n            | tar xzf -\n\n        pushd "${openssl_dir}"\n\n        options=(--prefix=${LIBPQ_BUILD_PREFIX} --openssldir=${LIBPQ_BUILD_PREFIX} \\\n            zlib -fPIC shared)\n        if [ -z "${MACOSX_ARCHITECTURE:-}" ]; then\n            ./config ${options[*]}\n        else\n            ./config "darwin64-$MACOSX_ARCHITECTURE-cc" ${options[*]}\n        fi\n\n        make -s depend\n        make -s\n    else\n        pushd "${openssl_dir}"\n    fi\n\n    # Install openssl\n    make install_sw\n    popd\n\n  fi\nfi\n\n\nif [ "$ID" == "macos" ]; then\n\n    # Build kerberos if needed\n    krb5_dir="krb5-${krb5_version}/src"\n    if [ ! -d "${krb5_dir}" ]; then\n        curl -fsSL "https://kerberos.org/dist/krb5/${krb5_version%.*}/krb5-${krb5_version}.tar.gz" \\\n            | tar xzf -\n\n        pushd "${krb5_dir}"\n        ./configure "${make_configure_standard_flags[@]}"\n        make -s\n    else\n        pushd "${krb5_dir}"\n    fi\n\n    make install\n    popd\n\nfi\n\n\nif [ "$ID" == "centos" ] || [ "$ID" == "almalinux" ]|| [ "$ID" == "macos" ]; then\n  if [[ ! -f "${LIBPQ_BUILD_PREFIX}/lib/libldap.${library_suffix}" ]]; then\n\n    # Build openldap if needed\n    ldap_tag="${ldap_version}"\n    ldap_dir="openldap-${ldap_tag}"\n    if [ ! -d "${ldap_dir}" ]; then\n        curl -fsSL \\\n            https://www.openldap.org/software/download/OpenLDAP/openldap-release/openldap-${ldap_tag}.tgz \\\n            | tar xzf -\n\n        pushd "${ldap_dir}"\n\n        ./configure "${make_configure_standard_flags[@]}" --enable-backends=no --enable-null\n\n        make -s depend\n        make -s -C libraries/liblutil/\n        make -s -C libraries/liblber/\n        make -s -C libraries/libldap/\n    else\n        pushd "${ldap_dir}"\n    fi\n\n    # Install openldap\n    make -C libraries/liblber/ install\n    make -C libraries/libldap/ install\n    make -C include/ install\n    chmod +x ${LIBPQ_BUILD_PREFIX}/lib/{libldap,liblber}*.${library_suffix}*\n    popd\n\n  fi\nfi\n\n\n# Build libpq if needed\npostgres_tag="REL_${postgres_version//./_}"\npostgres_dir="postgres-${postgres_tag}"\nif [ ! -d "${postgres_dir}" ]; then\n    curl -fsSL \\\n        https://github.com/postgres/postgres/archive/${postgres_tag}.tar.gz \\\n        | tar xzf -\n\n    pushd "${postgres_dir}"\n\n    # Change the gssencmode default to \'disable\' to avoid various troubles\n    # related to unwanted GSSAPI interaction. See #1136.\n    patch -f -p1 <<HERE\ndiff --git a/src/interfaces/libpq/fe-connect.c b/src/interfaces/libpq/fe-connect.c\nindex 454d2ea3fb7..52c64ba3292 100644\n--- a/src/interfaces/libpq/fe-connect.c\n+++ b/src/interfaces/libpq/fe-connect.c\n@@ -132,7 +132,7 @@ static int\tldapServiceLookup(const char *purl, PQconninfoOption *options,\n #define DefaultSSLNegotiation\t"postgres"\n #ifdef ENABLE_GSS\n #include "fe-gssapi-common.h"\n-#define DefaultGSSMode "prefer"\n+#define DefaultGSSMode "disable"\n #else\n #define DefaultGSSMode "disable"\n #endif\nHERE\n\n    if [ "$ID" != "macos" ]; then\n        # Match the default unix socket dir default with what defined on Ubuntu and\n        # Red Hat, which seems the most common location\n        sed -i \'s|#define DEFAULT_PGSOCKET_DIR .*\'\\\n\'|#define DEFAULT_PGSOCKET_DIR "/var/run/postgresql"|\' \\\n            src/include/pg_config_manual.h\n    fi\n\n    export LD_LIBRARY_PATH="${LIBPQ_BUILD_PREFIX}/lib:${LIBPQ_BUILD_PREFIX}/lib64"\n\n    ./configure "${make_configure_standard_flags[@]}" --sysconfdir=/etc/postgresql-common \\\n        --with-gssapi --with-openssl --with-pam --with-ldap \\\n        --without-readline --without-icu\n    make -s -C src/interfaces/libpq\n    make -s -C src/bin/pg_config\n    make -s -C src/include\nelse\n    pushd "${postgres_dir}"\nfi\n\n# Install libpq\nmake -C src/interfaces/libpq install\nmake -C src/bin/pg_config install\nmake -C src/include install\npopd\n\nfind ${LIBPQ_BUILD_PREFIX} -name \\*.${library_suffix}.\\* -type f -exec strip --strip-unneeded {} \\;\n',
            'tools/ci/wheel_linux_before_all.sh': '#!/bin/bash\n\n# Configure the libraries needed to build wheel packages on linux.\n# This script is designed to be used by cibuildwheel as CIBW_BEFORE_ALL_LINUX\n\nset -euo pipefail\n\ndir="$( cd "$( dirname "${BASH_SOURCE[0]}" )" && pwd )"\n\nsource /etc/os-release\n\n# Install PostgreSQL development files.\ncase "$ID" in\n    alpine)\n        # tzdata is required for datetime tests.\n        "${dir}/build_libpq.sh" > /dev/null\n        ;;\n\n    debian)\n        # Note that the pgdg doesn\'t have an aarch64 repository so wheels are\n        # build with the libpq packaged with Debian 9, which is 9.6.\n        if [ "$AUDITWHEEL_ARCH" != \'aarch64\' ]; then\n            echo "deb http://apt.postgresql.org/pub/repos/apt $VERSION_CODENAME-pgdg main" \\\n                > /etc/apt/sources.list.d/pgdg.list\n            # TODO: On 2021-11-09 curl fails on \'ppc64le\' with:\n            #   curl: (60) SSL certificate problem: certificate has expired\n            # Test again later if -k can be removed.\n            curl -fsSLk https://www.postgresql.org/media/keys/ACCC4CF8.asc \\\n                > /etc/apt/trusted.gpg.d/postgresql.asc\n        fi\n\n        apt-get update\n        apt-get -y upgrade\n        apt-get -y install libpq-dev flex\n        ;;\n\n    centos | almalinux)\n        "${dir}/build_libpq.sh" > /dev/null\n        ;;\n\n    *)\n        echo "$0: unexpected Linux distribution: \'$ID\'" >&2\n        exit 1\n        ;;\nesac\n',
        }
